#!/usr/bin/env bash
# Boosted Flavor CR - EMJ (electron + muon-jet), using EE.py --signal-scale 1.0
python EE.py --signal-scale 1.0 --hist "Obj_PU_pt(ll)_boosted_e_mujet_Flavor_CR" --ymin 10 --ymax 1e3 --output BoostFLVEMJ_pt --xmin 0 --xmax 1000 --xlabel "Dilepton p_{T} (GeV)" --rebin 50 --rmin 0 --rmax 2.5
python EE.py --signal-scale 1.0 --hist "Obj_PU_leading_fatjet_pt_boosted_e_mujet_Flavor_CR" --ymin 1 --ymax 3e3 --output BoostFLVEMJ_leading_fatjet_pt --xmin 0 --xmax 2000 --xlabel "Leading Fat Jet p_{T} (GeV)" --bins "200,400,600,800,1000,2000" --rmin 0 --rmax 2.5
python EE.py --signal-scale 1.0 --hist "Obj_PU_m(lljj)_boosted_e_mujet_Flavor_CR" --ymin 1 --ymax 1e3 --output BoostFLVEMJ_mlljj --xmin 800 --xmax 8000 --xlabel "m(lljj) (GeV)" --bins "800,1000,1200,1500,1800,8000" --rmin 0 --rmax 2.5
python EE.py --signal-scale 1.0 --hist "Obj_PU_Boosted_Flavor_CR_e_mujet_Fatjet_SDMass" --ymin 1 --ymax 1e3 --output BoostFLVEMJ_fatjet_SDMass --xmin 0 --xmax 200 --xlabel "Fat Jet Soft Drop Mass (GeV)" --rebin 2 --rmin 0 --rmax 2.5
python EE.py --signal-scale 1.0 --hist "Obj_PU_Boosted_Flavor_CR_e_mujet_LeadingLepPt" --ymin 1e-1 --ymax 1e6 --output BoostFLVEMJ_leading_lep_pt --xmin 0 --xmax 1000 --xlabel "Leading Lepton p_{T} (GeV)" --bins "50,90,130,170,210,250,290,310,350,390,430,470,510,550,590,630,670,710,750,790,830,870,910,950,1000,2000" --rmin 0 --rmax 2.5
python EE.py --signal-scale 1.0 --hist "Obj_PU_Boosted_Flavor_CR_e_mujet_SubLeadingLepPt" --ymin 1e-3 --ymax 1e6 --output BoostFLVEMJ_subleading_lep_pt --xmin 0 --xmax 500 --xlabel "Subleading Lepton p_{T} (GeV)" --bins "50,70,90,110,130,150,170,190,210,230,250,270,290,310,330,350,370,390,410,430,450,470,490,500" --rmin 0 --rmax 2.5
python EE.py --signal-scale 1.0 --hist "Obj_PU_Boosted_Flavor_CR_e_mujet_LeadingLepEta" --ymin 1 --ymax 1e3 --output BoostFLVEMJ_leading_lep_eta --xmin -2.5 --xmax 2.5 --xlabel "Leading Lepton #eta" --rebin 2 --rmin 0 --rmax 2.5
