python EE.py --signal-scale 1.0 --hist "Obj_PU_Boosted_Flavor_CR_e_mujet_Fatjet_Phi" --ymin 1 --ymax 1e3 --output BoostFLVEMJ_fatjet_phi --xmin -3.14 --xmax 3.14 --xlabel "Fat Jet #phi" --rebin 2 --rmin 0 --rmax 2.5
python EE.py --signal-scale 1.0 --hist "Obj_PU_Boosted_Flavor_CR e_mujet_DeltaR_LeadLep_Fatjet" --ymin 1 --ymax 1e3 --output BoostFLVEMJ_deltaR_leadlep_fatjet --xmin 0 --xmax 5 --xlabel "#DeltaR(lead lep, fat jet)" --rebin 2 --rmin 0 --rmax 2.5
