python EE.py --signal-scale 1.0 --hist "Obj_PU_Boosted_Flavor_CR_e_mujet_SubLeadingLepPhi" --ymin 1 --ymax 1e3 --output BoostFLVEMJ_subleading_lep_phi --xmin -3.14 --xmax 3.14 --xlabel "Subleading Lepton #phi" --rebin 2 --rmin 0 --rmax 2.5
