python EE.py --signal-scale 1.0 --hist "Obj_PU_Boosted_Flavor_CR_e_mujet_punum" --ymin 1 --ymax 1e3 --output BoostFLVEMJ_punum --xmin 0 --xmax 80 --xlabel "Number of Pileup Vertices" --rebin 2 --rmin 0 --rmax 2.5
python EE.py --signal-scale 1.0 --hist "Obj_PU_Boosted_Flavor_CR_e_mujet_jetnum" --ymin 1 --ymax 1e3 --output BoostFLVEMJ_jetnum --xmin 0 --xmax 20 --xlabel "Number of Jets" --rmin 0 --rmax 2.5

